export async function createAgentSession(options = {}) {
  const cwd = options.cwd ?? process.cwd();
  const agentDir = options.agentDir ?? getDefaultAgentDir();

  // 1️⃣  Load / create core services
  const authStorage   = options.authStorage ?? AuthStorage.create(join(agentDir, 'auth.json'));
  const modelRegistry = options.modelRegistry ?? ModelRegistry.create(authStorage, join(agentDir, 'models.json'));
  const settingsMgr   = options.settingsManager ?? SettingsManager.create(cwd, agentDir);
  const sessionMgr    = options.sessionManager ?? SessionManager.create(cwd, getDefaultSessionDir(cwd, agentDir));

  // 2️⃣  Load resources (extensions, skills, prompt‑templates, themes)
  let resourceLoader = options.resourceLoader;
  if (!resourceLoader) {
    resourceLoader = new DefaultResourceLoader({ cwd, agentDir, settingsManager: settingsMgr });
    await resourceLoader.reload();
  }

  // 3️⃣  Restore any existing session data
  const existingCtx = sessionMgr.buildSessionContext();
  const hasExisting = existingCtx.messages.length > 0;

  // 4️⃣  Resolve model (fallback logic, defaults, etc.)
  let model = options.model;
  if (!model && hasExisting && existingCtx.model) {
    const restored = modelRegistry.find(existingCtx.model.provider, existingCtx.model.modelId);
    if (restored && modelRegistry.hasConfiguredAuth(restored)) {
      model = restored;
    }
  }
  if (!model) {
    const result = await findInitialModel({ … });
    model = result.model;
  }

  // 5️⃣  Resolve thinking level
  let thinking = options.thinkingLevel ?? settingsMgr.getDefaultThinkingLevel() ?? DEFAULT_THINKING_LEVEL;
  if (!model?.reasoning) thinking = 'off';

  // 6️⃣  Build the Agent (core state machine)
  const agent = new Agent({
    initialState: { systemPrompt: '', model, thinkingLevel: thinking, tools: [] },
    convertToLlm: convertToLlmWithBlockImages,
    streamFn: async (model, context, opts) => {
      const auth = await modelRegistry.getApiKeyAndHeaders(model);
      return streamSimple(model, context, { ...opts, apiKey: auth.apiKey, headers: auth.headers });
    },
    // … other callbacks for extensions
  });

  // 7️⃣  Restore messages & thinking changes
  if (hasExisting) {
    agent.replaceMessages(existingCtx.messages);
    if (!sessionMgr.getBranch().some(e => e.type === 'thinking_level_change')) {
      sessionMgr.appendThinkingLevelChange(thinking);
    }
  } else {
    sessionMgr.appendModelChange(model.provider, model.id);
    sessionMgr.appendThinkingLevelChange(thinking);
  }

  // 8️⃣  Wrap the Agent in an AgentSession
  const session = new AgentSession({
    agent,
    sessionManager: sessionMgr,
    settingsManager: settingsMgr,
    cwd,
    scopedModels: options.scopedModels,
    resourceLoader,
    customTools: options.customTools,
    modelRegistry,
    initialActiveToolNames: options.tools?.map(t => t.name) ?? ['read', 'bash', 'edit', 'write'],
    extensionRunnerRef,
  });

  return { session, extensionsResult: resourceLoader.getExtensions(), modelFallbackMessage };
}
```

**What the SDK gives you**

| Feature | SDK support |
|---------|-------------|
| **Session persistence** | `SessionManager` writes a JSON file that can be resumed. |
| **Tool registry** | `core/tools/index.ts` exposes every built‑in tool and factories to create custom ones. |
| **Custom models** | `ModelRegistry` lets you add providers (Anthropic, OpenAI, Bedrock, etc.) and configure API keys. |
| **Prompt templates / skills** | `ResourceLoader` loads files from `~/.pi/skills`, `~/.pi/templates`, `~/.pi/extensions`. |
| **Themes** | `initTheme` loads a theme package and watches it for changes. |
| **Modes** | `modes/index.ts` implements the interactive TUI, JSON output, RPC mode, and the SDK mode itself. |
| **Extensibility** | The SDK exposes `extensionRunnerRef` for plugins to register before‑request hooks or transform the context. |
| **Type safety** | All public functions are typed. `AgentSession` implements the `AgentSession` interface which you can consume in your own code. |

### 2. Example usage of the SDK

```ts
import { createAgentSession, readTool, bashTool } from '@mariozechner/pi-coding-agent';

(async () => {
  const { session } = await createAgentSession({
    cwd: process.cwd(),
    tools: [readTool, bashTool],   // add any built‑in tools you need
    model: { provider: 'anthropic', modelId: 'claude-3-haiku-20240307' },
  });

  // Send a user message
  await session.sendUserMessage('Create a test file.');

  // Process the assistant turn (this will automatically invoke the tools)
  await session.processTurn();

  // Get the assistant’s final answer
  console.log(session.getAssistantLastMessage().content);
})();
```

