### Pi – `createAgentSession` (Node/TS)

```ts
import { createAgentSession } from '@mariozechner/pi-coding-agent';
import { readTool, writeTool, bashTool } from '@mariozechner/pi-coding-agent';

async function main() {
  // Minimal session (uses defaults)
  const { session } = await createAgentSession();

  // Send a message and get a streaming response
  for await (const part of session.send('Hello')) {
    process.stdout.write(part.content ?? '');
  }

  // Access tools or add custom ones
  session.agent.addTools([readTool, writeTool, bashTool]);
